import React, { useState, useEffect } from 'react';

function Login({ onLogin }) {
  const [view, setView] = useState('landing'); // landing, login, signup-buyer, signup-seller
  const [index, setIndex] = useState(0);

  // Slider Logic
  const images = [
    "https://images.unsplash.com/photo-1610348725531-843dff563e2c?auto=format&fit=crop&q=80&w=600",
    "https://images.unsplash.com/photo-1518977676601-b53f02ac6d31?auto=format&fit=crop&q=80&w=600",
    "https://images.unsplash.com/photo-1464226184884-fa280b87c399?auto=format&fit=crop&q=80&w=600"
  ];

  useEffect(() => {
    const timer = setInterval(() => {
      setIndex((prev) => (prev < images.length - 1 ? prev + 1 : 0));
    }, 3000);
    return () => clearInterval(timer);
  }, [images.length]);

  const handleAuth = (role) => {
    onLogin({ role, name: "User" });
  };

  return (
    <div className="container-fluid vh-100 p-0 d-flex overflow-hidden" style={{ backgroundColor: '#f8fdf5' }}>

      {/* LEFT SIDE: SLIDER & BRANDING */}
      <div className="col-md-6 d-none d-md-flex flex-column justify-content-center align-items-center text-white" 
           style={{ backgroundColor: '#75B946', position: 'relative' }}>
        <div style={{ width: '300px', height: '400px', overflow: 'hidden', borderRadius: '20px', boxShadow: '0 10px 30px rgba(0,0,0,0.2)' }}>
          <div style={{ display: 'flex', transition: 'transform 0.5s ease-in-out', transform: `translateX(-${index * 300}px)` }}>
            {images.map((img, i) => (
              <img key={i} src={img} alt="Agri" style={{ width: '300px', height: '400px', objectFit: 'cover' }} />
            ))}
          </div>
        </div>
        <h1 className="mt-4 fw-bold">Agri-AI Platform</h1>
        <p className="px-5 text-center">Empowering Farmers & Buyers with AI-Driven Data.</p>
      </div>

      {/* RIGHT SIDE: AUTH FORMS */}
      <div className="col-12 col-md-6 d-flex align-items-center justify-content-center p-4">
        <div className="card shadow-lg border-0 p-4 w-100" style={{ maxWidth: '450px', borderRadius: '20px' }}>

          {/* LANDING VIEW: LOGIN OR SIGNUP */}
          {view === 'landing' && (
            <div className="text-center">
              <h2 className="mb-4" style={{ color: '#46B951' }}>Welcome Back</h2>
              <button className="btn w-100 mb-3 text-white shadow-sm" style={{ backgroundColor: '#75B946' }} onClick={() => setView('login')}>Login</button>
              <div className="d-flex gap-2">
                <button className="btn btn-outline-success w-50" onClick={() => setView('signup-buyer')}>Join as Buyer</button>
                <button className="btn btn-outline-dark w-50" onClick={() => setView('signup-seller')}>Join as Seller</button>
              </div>
            </div>
          )}

          {/* LOGIN FORM */}
          {view === 'login' && (
            <form onSubmit={(e) => { e.preventDefault(); handleAuth('buyer'); }}>
              <h3 className="mb-3">Login</h3>
              <input type="text" className="form-control mb-3" placeholder="Email or Mobile No" required />
              <input type="password" className="form-control mb-3" placeholder="Password" required />
              <button className="btn w-100 text-white" style={{ backgroundColor: '#46B951' }}>Enter Platform</button>
              <button className="btn btn-link mt-2 w-100" onClick={() => setView('landing')}>Go Back</button>
            </form>
          )}

          {/* SIGNUP FORM (Common & Specific) */}
          {(view === 'signup-buyer' || view === 'signup-seller') && (
            <form onSubmit={(e) => { e.preventDefault(); handleAuth(view === 'signup-buyer' ? 'buyer' : 'seller'); }}>
              <h3 className="mb-3">{view === 'signup-buyer' ? 'Buyer' : 'Seller'} Registration</h3>
              <input type="text" className="form-control mb-2" placeholder="Full Name" required />
              <input type="email" className="form-control mb-2" placeholder="Email Address" required />
              <input type="text" className="form-control mb-2" placeholder="Mobile No" required />
              <input type="text" className="form-control mb-2" placeholder="Location" required />

              {/* Conditional Seller Fields */}
              {view === 'signup-seller' && (
                <>
                  <input type="text" className="form-control mb-2" placeholder="Aadhar / PAN No" required />
                  <div className="mb-2">
                    <label className="small text-muted">Income Proof (PDF/Image)</label>
                    <input type="file" className="form-control" required />
                  </div>
                </>
              )}

              {/* Interests (Optional) */}
              <input type="text" className="form-control mb-3" placeholder="Fav Fruits/Vegetables (Optional)" />

              <button className="btn w-100 text-white" style={{ backgroundColor: '#AEB946' }}>Create Account</button>
              <button className="btn btn-link mt-1 w-100 text-muted" onClick={() => handleAuth(view.split('-')[1])}>Skip for now</button>
              <button className="btn btn-link w-100" onClick={() => setView('landing')}>Cancel</button>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}

export default Login;
